def repeating(t, n):
    num_digits = len(str(n))
    if num_digits % t != 0:
        return False
    pattern = n % (10**t)
    temp = n
    while temp > 0:
        if temp % (10**t) != pattern:
            return False
        temp //= (10**t)
    return True

