def unique_digits(n):
    def has_digit(n, k):
        assert k >= 0 and k < 10
        while n > 0:
            if n % 10 == k:
                return True
            n //= 10
        return False
    count = 0
    for d in range(10):
        if has_digit(n, d):
            count += 1
    return count

